const rows = $input.all().map(i => i.json);
const today = new Date().toISOString().slice(0, 10);
const webhook = $env.SLACK_WEBHOOK_URL || '';

function reasons(r) {
  const m = r.match_reasons;
  if (Array.isArray(m)) return m.slice(0, 4).join(', ');
  return m ? String(m) : '';
}

const header = `*GovBid review digest* — ${today}\n${rows.length} opportunities (sync params with match-profile.yaml)`;
const blocks = [
  { type: 'section', text: { type: 'mrkdwn', text: header } },
  { type: 'divider' },
];

if (rows.length === 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '_No opportunities matched filters today._' } });
} else {
  rows.forEach((r, i) => {
    const title = (r.title || 'Untitled').slice(0, 120);
    const deadline = r.response_deadline ? new Date(r.response_deadline).toISOString().slice(0, 10) : 'N/A';
    const link = r.ui_link || '';
    let text = `*${i + 1}. [${r.rule_score}] ${title}*\n${r.agency || 'N/A'} | deadline ${deadline}\n_${reasons(r)}_`;
    if (link) text += `\n<${link}|SAM.gov>`;
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text } });
  });
}

let slack_sent = false;
if (webhook) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: webhook,
    headers: { 'Content-Type': 'application/json' },
    body: { blocks },
  });
  slack_sent = true;
}

let md = `# Gov Contracts Review Digest\n\nDate: ${today}\n\nFound **${rows.length}** opportunities.\n\n`;
for (const r of rows) {
  const deadline = r.response_deadline ? new Date(r.response_deadline).toISOString().slice(0, 10) : 'N/A';
  md += `## ${r.title || 'Untitled'}\n- Score: ${r.rule_score} | Deadline: ${deadline}\n- [SAM.gov](${r.ui_link || '#'})\n\n`;
}
const fs = require('fs');
const filePath = `/data/review-digest-${today}.md`;
fs.writeFileSync(filePath, md, 'utf8');

return [{ json: { file_path: filePath, count: rows.length, slack_sent } }];
